import React from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip, Grid } from '@mui/material';
import response from './response.json';

interface VolunteerHours {
  total: number;
  thisWeek: number;
  averagePerWeek: number;
}

interface ImpactMetric {
  metric: string;
  count: number;
}

interface UpcomingEvent {
  date: string;
  event: string;
  location: string;
}

interface VolunteerData {
  loggedHours: VolunteerHours;
  impactMetrics: ImpactMetric[];
  upcomingEvents: UpcomingEvent[];
}

export default function Widget() {
  const volunteerData = response.data as VolunteerData;
  const { loggedHours, impactMetrics, upcomingEvents } = volunteerData;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 450, bgcolor: '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" fontWeight={600} sx={{ color: '#4CAF50' }}>
              Volunteer Hours
            </Typography>
            <Stack direction="row" spacing={2}>
              <Box>
                <Typography variant="body2" color="text.secondary">
                  Total
                </Typography>
                <Typography variant="h5" fontWeight={700}>
                  {loggedHours.total}
                </Typography>
              </Box>
              <Box>
                <Typography variant="body2" color="text.secondary">
                  This Week
                </Typography>
                <Typography variant="h5" fontWeight={700}>
                  {loggedHours.thisWeek}
                </Typography>
              </Box>
              <Box>
                <Typography variant="body2" color="text.secondary">
                  Avg/Week
                </Typography>
                <Typography variant="h5" fontWeight={700}>
                  {loggedHours.averagePerWeek}
                </Typography>
              </Box>
            </Stack>
          </Box>

          <Box>
            <Typography variant="h6" fontWeight={600} sx={{ color: '#FFC107' }}>
              Impact Metrics
            </Typography>
            <Grid container spacing={1}>
              {impactMetrics.map((metric, index) => (
                <Grid item xs={6} key={index}>
                  <Chip label={`${metric.metric}: ${metric.count}`} sx={{ width: '100%', fontSize: '10px' }} />
                </Grid>
              ))}
            </Grid>
          </Box>

          <Box>
            <Typography variant="h6" fontWeight={600} sx={{ color: '#4CAF50' }}>
              Upcoming Events
            </Typography>
            <Stack spacing={0.5}>
              {upcomingEvents.map((event, index) => (
                <Box key={index}>
                  <Typography variant="body2" color="text.secondary">
                    {event.date}
                  </Typography>
                  <Typography variant="body2" fontWeight={500}>
                    {event.event} at {event.location}
                  </Typography>
                </Box>
              ))}
            </Stack>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
